// The product's interactive face - generated by the AI OS UI Synthesizer.
// Vanilla JS; imports the synthesized brain. No framework, no per-user image gen.
import { runCapability } from "./capability.mjs";
import { renderCard } from "./card.mjs";

const CONFIG = {
  "questions": [
    "What's your most authentic strength?",
    "What shadow trait do you acknowledge?",
    "What's a vivid metaphor for you?",
    "What word describes your current essence?",
    "What quality are you growing into?"
  ],
  "askName": true,
  "hasCard": true,
  "capture": {
    "enabled": true,
    "unlocks": "the full result"
  },
  "resultFields": [
    "archetype_name",
    "one_line_essence",
    "visual_metaphor",
    "strengths",
    "shadow_traits",
    "motto / chapter theme-word",
    "narrative"
  ],
  "productName": "Alter Ego",
  "intro": "Free, forever. Answer 5 quick, revealing questions and meet your Alter Ego.",
  "share": {
    "url": "https://macleanmarket.com/alterego",
    "cta": "What's your Alter Ego?"
  },
  "marketLink": {
    "label": "More from MacLean Market",
    "url": "https://macleanmarket.com"
  },
  "rewardCards": [
    {
      "id": "friend_group_ego",
      "label": "Friend Group Ego",
      "kind": "card",
      "lens": "friend_group"
    },
    {
      "id": "shadow_ego",
      "label": "Shadow Ego",
      "kind": "card",
      "lens": "shadow"
    }
  ],
  "bioLine": {
    "enabled": true,
    "linkedin": false
  }
};
const RENDER_CARD = renderCard;

const $ = (t, attrs, kids) => {
  const el = document.createElement(t);
  for (const k in (attrs || {})) {
    if (k === "style") Object.assign(el.style, attrs[k]);
    else if (k === "class") el.className = attrs[k];
    else if (k === "html") el.innerHTML = attrs[k];
    else el.setAttribute(k, attrs[k]);
  }
  for (const c of (kids || [])) el.appendChild(typeof c === "string" ? document.createTextNode(c) : c);
  return el;
};
const sp = (n) => "var(--aios-space-" + n + ", " + (n * 0.25) + "rem)";

function fieldLabel(name) { return String(name).replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase()); }

function root() { return document.getElementById("aios-app-root"); }
function clear() { const r = root(); if (r) r.innerHTML = ""; return r; }

// ---- questionnaire screen ----
function renderQuestions() {
  const r = clear(); if (!r) return;
  r.setAttribute("data-screen", "questions");
  const form = $("form", { "data-aios-form": "1", class: "aios-quiz", style: { display: "flex", flexDirection: "column", gap: sp(4), maxWidth: "40rem", margin: "0 auto" } });
  // Fix 1: NO intro here - the SSR shell already shows the product name + intro
  // above #aios-app-root; rendering it again duplicated it.
  const inputs = [];
  if (CONFIG.askName) {
    const wrap = $("label", { class: "aios-q" });
    wrap.appendChild($("span", { class: "aios-q-text" }, ["Your name (optional)"]));
    const inp = $("input", { type: "text", name: "aios-name", "data-aios-name": "1", autocomplete: "given-name", class: "aios-input", placeholder: "First name" });
    wrap.appendChild(inp); form.appendChild(wrap); form._name = inp;
  }
  CONFIG.questions.forEach((q, i) => {
    const wrap = $("label", { class: "aios-q" });
    wrap.appendChild($("span", { class: "aios-q-text" }, [(i + 1) + ". " + q]));
    const inp = $("input", { type: "text", name: "aios-q" + i, "data-aios-q": String(i), required: "true", class: "aios-input", placeholder: "Type your answer…" });
    wrap.appendChild(inp); form.appendChild(wrap); inputs.push(inp);
  });
  const btn = $("button", { type: "submit", "data-aios-submit": "1", class: "aios-submit" }, ["See my result →"]);
  form.appendChild(btn);
  form.addEventListener("submit", async (e) => {
    e.preventDefault();
    const answers = inputs.map((x) => (x.value || "").trim());
    if (answers.some((a) => !a)) { return; }
    const firstName = form._name ? (form._name.value || "").trim() : "";
    btn.disabled = true; btn.textContent = "Reading...";
    try {
      const reading = await runCapability({ answers: answers, firstName: firstName, businessName: firstName });
      renderResult(reading, { answers, firstName });
    } catch (err) {
      const r2 = root(); if (r2) r2.appendChild($("p", { style: { color: "var(--aios-color-warning,#b45309)" } }, ["Something went wrong generating your result."]));
      btn.disabled = false; btn.textContent = "See my result";
    }
  });
  r.appendChild(form);
}

// ---- deterministic templated card (the factory's guaranteed, $0 share-worthy
// card, built from the reading DATA). Used whenever the synthesized renderCard is
// absent or returns something invalid (e.g. bare CSS with no markup). Horizontal:
// it reads CONFIG.resultFields + the reading object, carries no venture strings.
function esc(s) {
  return String(s).replace(/[&<>"']/g, function (c) {
    return ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" })[c];
  });
}
var TC_GRADS = [
  "linear-gradient(135deg,#6a11cb,#2575fc)", "linear-gradient(135deg,#8e2de2,#4a00e0)",
  "linear-gradient(135deg,#0f2027,#2c5364)", "linear-gradient(135deg,#11998e,#38ef7d)",
  "linear-gradient(135deg,#c31432,#240b36)", "linear-gradient(135deg,#f7971e,#c1440e)",
  "linear-gradient(135deg,#1a2980,#26d0ce)", "linear-gradient(135deg,#ee0979,#ff6a00)"
];
function tcGrad(seed) {
  var s = 0, str = String(seed || "");
  for (var i = 0; i < str.length; i++) s = (s + str.charCodeAt(i)) % 9973;
  return TC_GRADS[s % TC_GRADS.length];
}
var TEMPLATED_CARD_CSS =
  ".aios-tc{position:relative;max-width:34rem;margin:0 auto;padding:2rem 1.75rem;border-radius:18px;color:#fff;" +
  "font-family:inherit;box-shadow:0 18px 44px -14px rgba(0,0,0,.5);overflow:hidden}" +
  ".aios-tc::before{content:'';position:absolute;inset:0;background:radial-gradient(130% 80% at 100% 0,rgba(255,255,255,.20),transparent 60%);pointer-events:none}" +
  ".aios-tc>*{position:relative}" +
  ".aios-tc-kicker{text-transform:uppercase;letter-spacing:.18em;font-size:.7rem;opacity:.82;margin:0 0 .55rem}" +
  ".aios-tc-headline{font-size:2rem;line-height:1.1;font-weight:800;margin:0 0 .4rem;text-shadow:0 2px 14px rgba(0,0,0,.28)}" +
  ".aios-tc-sub{font-size:1.1rem;font-style:italic;opacity:.95;margin:0 0 1.3rem;line-height:1.4}" +
  ".aios-tc-sec{margin:0 0 1rem}" +
  ".aios-tc-label{text-transform:uppercase;letter-spacing:.12em;font-size:.64rem;opacity:.72;margin:0 0 .3rem}" +
  ".aios-tc-val{font-size:1rem;line-height:1.5;margin:0;white-space:pre-wrap}" +
  ".aios-tc-chips{display:flex;flex-wrap:wrap;gap:.4rem;margin:.15rem 0 0;padding:0;list-style:none}" +
  ".aios-tc-chip{background:rgba(255,255,255,.16);border:1px solid rgba(255,255,255,.30);border-radius:999px;padding:.28rem .72rem;font-size:.85rem}" +
  ".aios-tc-foot{margin:1.4rem 0 0;padding-top:1rem;border-top:1px solid rgba(255,255,255,.22);font-size:.7rem;letter-spacing:.14em;text-transform:uppercase;opacity:.78}";
function tcSection(label, value) {
  if (value == null || value === "") return "";
  if (Array.isArray(value)) {
    var items = value.filter(function (v) { return v != null && v !== ""; });
    if (!items.length) return "";
    var chips = items.map(function (v) { return '<li class="aios-tc-chip">' + esc(String(v)) + "</li>"; }).join("");
    return '<div class="aios-tc-sec"><p class="aios-tc-label">' + esc(label) + '</p><ul class="aios-tc-chips">' + chips + "</ul></div>";
  }
  return '<div class="aios-tc-sec"><p class="aios-tc-label">' + esc(label) + '</p><p class="aios-tc-val">' + esc(String(value)) + "</p></div>";
}
// fieldsOpt overrides the field ORDER (reward cards carry their own fields, not
// the main result_fields); kicker overrides the small top label (e.g. "Shadow Ego").
function renderTemplatedCard(reading, fieldsOpt, kicker) {
  reading = reading || {};
  var fields = (fieldsOpt && fieldsOpt.length)
    ? fieldsOpt.filter(function (f) { return fieldPresent(reading, f); })
    : pickFields(reading);
  var headField = fields[0];
  var headline = headField ? reading[headField] : (CONFIG.productName || "Your result");
  if (Array.isArray(headline)) headline = headline.join(", ");
  var rest = fields.slice(1);
  var subField = null;
  for (var i = 0; i < rest.length; i++) {
    var v = reading[rest[i]];
    if (typeof v === "string" && v.length > 0 && v.length <= 140) { subField = rest[i]; break; }
  }
  var secHtml = "";
  for (var j = 0; j < rest.length; j++) {
    if (rest[j] === subField) continue;
    secHtml += tcSection(fieldLabel(rest[j]), reading[rest[j]]);
  }
  var kick = kicker || CONFIG.productName;
  var grad = tcGrad((kicker ? kicker + "|" : "") + headline);
  var html =
    '<article class="aios-tc" data-aios-templated-card="1" style="background:' + grad + '">' +
    (kick ? '<p class="aios-tc-kicker">' + esc(kick) + "</p>" : "") +
    '<h2 class="aios-tc-headline">' + esc(String(headline)) + "</h2>" +
    (subField ? '<p class="aios-tc-sub">' + esc(String(reading[subField])) + "</p>" : "") +
    '<div class="aios-tc-body">' + secHtml + "</div>" +
    // FIX 5: the "your result - keep or share" foot line is removed. The card's
    // affordances (Share / Add-to-bio / market) are appended by the client as a
    // data-no-share bar INSIDE this article, so they are never baked into the
    // shareable card image.
    "</article>";
  return { html: html, css: TEMPLATED_CARD_CSS };
}

// ---- Wave-2: share (the growth loop), polished reveal, market link ----
function fieldPresent(reading, k) { const v = reading[k]; return v != null && v !== "" && !(Array.isArray(v) && !v.length); }
function pickFields(reading) {
  reading = reading || {};
  // Prefer the declared result fields, but a card with its OWN field shape (a
  // reward card) falls back to its own keys - so every card renders correctly.
  const rf = (CONFIG.resultFields && CONFIG.resultFields.length) ? CONFIG.resultFields.filter((k) => fieldPresent(reading, k)) : [];
  if (rf.length) return rf;
  return Object.keys(reading).filter((k) => fieldPresent(reading, k));
}
function cardHeadline(reading) {
  const f = pickFields(reading); const v = reading[f[0]];
  return Array.isArray(v) ? v.join(", ") : (v == null ? "" : String(v));
}
function cardEssence(reading) {
  const f = pickFields(reading);
  for (let i = 1; i < f.length; i++) { const v = reading[f[i]]; if (typeof v === "string" && v.length > 0 && v.length <= 160) return v; }
  return "";
}
// Pre-filled share text: the archetype + one-line essence + the market link, so
// the user taps post and never writes the caption.
function shareCaption(reading, title) {
  const head = title || cardHeadline(reading);
  const ess = cardEssence(reading);
  const text = ess ? (head + " \u2014 " + ess) : head;
  const url = CONFIG.share && CONFIG.share.url ? CONFIG.share.url : "";
  return url ? (text + "\n\n" + url) : text;
}
async function doShare(caption) {
  try { if (navigator.share) { await navigator.share({ text: caption }); return "shared"; } }
  catch (e) { if (e && e.name === "AbortError") return "cancelled"; }
  try { await navigator.clipboard.writeText(caption); return "copied"; }
  catch (e) { return "failed"; }
}
// B3: the pre-filled post SPLIT into text + url, for the web-intent links (which
// take the text and the url as separate params).
function shareParts(reading, title) {
  const head = title || cardHeadline(reading);
  const ess = cardEssence(reading);
  const text = ess ? (head + " \u2014 " + ess) : head;
  const url = CONFIG.share && CONFIG.share.url ? CONFIG.share.url : "";
  return { text: text, url: url };
}
// Direct web-share intents. X pre-fills BOTH text + url; LinkedIn's share-offsite
// endpoint only accepts the url (it ignores a text param), so it gets the link.
function xIntentUrl(text, url) {
  let u = "https://twitter.com/intent/tweet?text=" + encodeURIComponent(text || "");
  if (url) u += "&url=" + encodeURIComponent(url);
  return u;
}
function linkedInIntentUrl(url) {
  return "https://www.linkedin.com/sharing/share-offsite/?url=" + encodeURIComponent(url || "");
}
// The polished, DESIGNED on-screen reading (used only for NO-CARD products; card
// products show the reading inside the card itself).
function renderReading(reading, fields) {
  const wrap = $("div", { "data-aios-fields": "full", "data-aios-reading": "1", class: "aios-reading" });
  for (const f of fields) {
    const v = reading[f];
    if (v == null || v === "") continue;
    const sec = $("div", { class: "aios-reading-sec" });
    sec.appendChild($("p", { class: "aios-reading-label" }, [fieldLabel(f)]));
    if (Array.isArray(v)) {
      const ul = $("ul", { class: "aios-reading-chips" });
      for (const item of v) { if (item != null && item !== "") ul.appendChild($("li", { class: "aios-reading-chip" }, [String(item)])); }
      sec.appendChild(ul);
    } else {
      sec.appendChild($("p", { class: "aios-reading-val" }, [String(v)]));
    }
    wrap.appendChild(sec);
  }
  return wrap;
}
// The tertiary "More from MacLean Market ->" link (quiet footer-weight).
function renderMarketLink() {
  if (!CONFIG.marketLink || !CONFIG.marketLink.url) return null;
  const wrap = $("div", { class: "aios-market-wrap" });
  wrap.appendChild($("a", { class: "aios-market-link", href: CONFIG.marketLink.url, target: "_blank", rel: "noreferrer" }, [
    (CONFIG.marketLink.label || "More from MacLean Market") + " \u2192",
  ]));
  return wrap;
}
// Per-card bio line: the MAIN card uses the engine's polished bio_line (two
// first-person sentences); each reward card uses its OWN engine bio_line (also
// two first-person sentences, in that card's voice). Same hard rules: no emoji,
// no archetype title, ~120-260 chars.
function perCardBio(reading, opts) {
  // Fix 3: the bio comes from the ENGINE (first-person, no archetype title). Main
  // card: the top-level reading.bio_line (passed as opts.mainBio). Reward card: its
  // OWN bio_line. If the engine produced none, show no bio row - never a fabricated
  // title-leading line.
  const b = (opts && opts.mainBio != null) ? opts.mainBio : (reading && reading.bio_line);
  if (b == null || b === "") return null;
  return bioLineData({ bio_line: b });
}
// One "Add to your bio" row: the line + a one-click Copy.
function inCardBioRow(label, text) {
  const row = $("div", { class: "aios-incard-bio", "data-aios-bioline": "1" });
  row.appendChild($("p", { class: "aios-incard-biolabel" }, [label]));
  row.appendChild($("p", { class: "aios-incard-biotext", "data-aios-bio-text": "1" }, [text]));
  const btn = $("button", { type: "button", "data-aios-copy": "1", class: "aios-incard-copy" }, ["Copy"]);
  const note = $("span", { "aria-live": "polite", class: "aios-incard-copynote" });
  btn.addEventListener("click", async () => {
    try { await navigator.clipboard.writeText(text); note.textContent = "Copied!"; }
    catch (e) { note.textContent = "Select to copy."; }
  });
  const bar = $("div", { class: "aios-incard-copyrow" }); bar.appendChild(btn); bar.appendChild(note);
  row.appendChild(bar);
  return row;
}
// The affordances that live INSIDE the card frame (FIX 3,4,2,6), marked
// data-no-share so they are EXCLUDED from the shareable card image.
function buildCardActions(reading, opts) {
  opts = opts || {};
  const bar = $("div", { class: "aios-tc-actions", "data-no-share": "1" });
  // B3: Share must actually help people POST. Primary = COPY the pre-filled post
  // (archetype + essence + link) to the clipboard - reliable EVERYWHERE, the
  // default. Plus direct web-intent links to X + LinkedIn (new tab, pre-filled
  // where the platform allows). navigator.share stays as an ADDITIONAL option
  // where supported (mobile), never the only path. The pre-filled CAPTION is the
  // archetype + one-line essence + link; each of the cards shares its OWN.
  const label = opts.label || CONFIG.productName || "card";
  const note = $("span", { "aria-live": "polite", class: "aios-incard-note" });
  // Primary: copy to clipboard.
  const btn = $("button", { type: "button", "data-aios-share-btn": "1", "data-aios-share-copy": "1", class: "aios-incard-share" }, ["Share your " + label]);
  btn.addEventListener("click", async () => {
    const cap = shareCaption(reading, cardHeadline(reading));
    try { await navigator.clipboard.writeText(cap); note.textContent = "Copied - paste it into your post."; }
    catch (e) { note.textContent = "Copy this: " + cap; }
  });
  // Direct web-share intents (new tab).
  const parts = shareParts(reading, cardHeadline(reading));
  const xLink = $("a", { class: "aios-incard-intent", "data-aios-share-x": "1", href: xIntentUrl(parts.text, parts.url), target: "_blank", rel: "noreferrer" }, ["Share to X"]);
  const liLink = $("a", { class: "aios-incard-intent", "data-aios-share-linkedin": "1", href: linkedInIntentUrl(parts.url || parts.text), target: "_blank", rel: "noreferrer" }, ["Share to LinkedIn"]);
  const intents = $("div", { class: "aios-incard-intents" });
  intents.appendChild(xLink); intents.appendChild(liLink);
  // Additional native share where the device supports it well (mobile).
  if (typeof navigator !== "undefined" && navigator.share) {
    const nativeBtn = $("button", { type: "button", "data-aios-share-native": "1", class: "aios-incard-intent" }, ["Share\u2026"]);
    nativeBtn.addEventListener("click", async () => {
      const cap = shareCaption(reading, cardHeadline(reading));
      const r = await doShare(cap);
      note.textContent = r === "shared" ? "Shared!" : r === "copied" ? "Copied - paste it into your post." : r === "cancelled" ? "" : cap;
    });
    intents.appendChild(nativeBtn);
  }
  const shareRow = $("div", { class: "aios-incard-sharerow" });
  shareRow.appendChild(btn); shareRow.appendChild(intents);
  bar.appendChild(shareRow);
  bar.appendChild(note);
  // FIX 2: a SINGLE add-to-bio line + Copy on this card (no separate LinkedIn line),
  // labeled "Add this to any bio".
  const bio = perCardBio(reading, opts);
  if (bio && bio.universal) {
    bar.appendChild(inCardBioRow("Add this to any bio", bio.universal));
  }
  // FIX 6: a quiet per-card market link (in addition to the page footer).
  if (CONFIG.marketLink && CONFIG.marketLink.url) {
    bar.appendChild($("a", { class: "aios-incard-market", "data-aios-market": "1", href: CONFIG.marketLink.url, target: "_blank", rel: "noreferrer" }, [
      (CONFIG.marketLink.label || "More from MacLean Market") + " \u2192",
    ]));
  }
  return bar;
}
// Build a full card (templated renderer) with its in-card affordances. Unified for
// the main card AND the reward cards, so every card is controllable + consistent
// and the affordances always sit INSIDE the gradient frame.
function buildCardElement(reading, opts) {
  opts = opts || {};
  // A reward card renders its own fields, but NOT bio_line - that is an affordance
  // (the "Add this to any bio" row), not card-body content (it duplicated otherwise).
  const rewardFields = opts.reward ? Object.keys(reading).filter((k) => k !== "bio_line" && k !== "reward_cards") : null;
  const tc = renderTemplatedCard(reading, rewardFields, opts.label || CONFIG.productName);
  const holder = $("div", { style: { display: "contents" } });
  holder.appendChild($("style", { html: tc.css }));
  const cardDiv = $("div", { "data-aios-card": "1", "data-aios-card-source": "templated", style: { maxWidth: "100%", overflowX: "auto" }, html: tc.html });
  if (opts.reward) cardDiv.setAttribute("data-aios-reward-card", "1");
  holder.appendChild(cardDiv);
  const article = cardDiv.querySelector(".aios-tc");
  if (article && CONFIG.hasCard) article.appendChild(buildCardActions(reading, opts));
  return holder;
}

// ---- Wave-2: capture-reward cards (the value-for-email) ----
// The reward cards' DATA comes from the ENGINE (reading.reward_cards[id]) - the
// factory never fabricates a distinct reading client-side. If the engine did not
// produce a declared reward card, that is an HONEST GAP the runner/gate catches
// (the reward reveal fails), not something we paper over.
function rewardCardData(reading, rc) {
  const bag = reading && reading.reward_cards;
  if (bag && bag[rc.id] && typeof bag[rc.id] === "object") return bag[rc.id];
  if (reading && reading[rc.id] && typeof reading[rc.id] === "object") return reading[rc.id];
  return null;
}
// Render every declared reward card that the engine produced, each an independent
// card with its OWN in-card Share / bio / market affordances. Returns how many.
function renderRewardCards(reading, into) {
  let n = 0;
  const mainHead = String(cardHeadline(reading) || "").trim().toLowerCase();
  for (const rc of (CONFIG.rewardCards || [])) {
    const data = rewardCardData(reading, rc);
    const sec = $("div", { "data-aios-reward": rc.id, style: { display: "flex", flexDirection: "column", gap: sp(2) } });
    if (!data) {
      // Honest gap - never a fabricated card.
      sec.appendChild($("p", { style: { fontSize: "0.85rem", opacity: "0.65", margin: "0" } }, [(rc.label || fieldLabel(rc.id)) + ": not produced for this build yet."]));
      sec.setAttribute("data-aios-reward-missing", "1");
    } else {
      const head = String(cardHeadline(data) || "").trim().toLowerCase();
      // Distinctness: a reward card that just restates the main card is a fail.
      if (head && head === mainHead) sec.setAttribute("data-aios-reward-redundant", "1");
      sec.appendChild(buildCardElement(data, { label: rc.label || fieldLabel(rc.id), reward: true }));
      n++;
    }
    into.appendChild(sec);
  }
  return n;
}
// ---- Wave-2: the bio line (a copyable self-descriptor to append to a social bio) ----
// Data from the ENGINE (reading.bio_line: a string, or { universal, linkedin }).
// Defensive: strip emoji and hard-cap length. The bio is now TWO first-person
// sentences (~120-260 chars), so the cap is 280 - it guards against a runaway
// engine, never truncates a well-formed two-sentence bio.
function sanitizeBio(s) {
  var t = String(s || "").replace(/[\u{1F000}-\u{1FAFF}\u{2600}-\u{27BF}\u{2190}-\u{21FF}\u{2B00}-\u{2BFF}\uFE0F]/gu, "").replace(/\s+/g, " ").trim();
  if (t.length > 280) t = t.slice(0, 277).replace(/\s+\S*$/, "") + "…";
  return t;
}
function bioLineData(reading) {
  var b = reading && reading.bio_line;
  if (!b) return null;
  if (typeof b === "string") return { universal: sanitizeBio(b) };
  if (typeof b === "object") return { universal: sanitizeBio(b.universal || b.line || ""), linkedin: b.linkedin ? sanitizeBio(b.linkedin) : "" };
  return null;
}
// The tease that earns the email: name the reward in enticing plain copy. The
// main card (with its reading) is already visible, so the email unlocks the bonus
// egos.
function captureTeaseText() {
  const labels = (CONFIG.rewardCards || []).map((rc) => rc.label || fieldLabel(rc.id)).filter(Boolean);
  if (!labels.length) return "Enter your email to unlock your full result.";
  const joined = labels.length === 1 ? labels[0]
    : labels.slice(0, -1).join(", ") + " and " + labels[labels.length - 1];
  return "Enter your email to unlock your " + joined + ".";
}

// ---- result screen (teaser card) + capture ----
function renderResult(reading, ctx) {
  const r = clear(); if (!r) return;
  r.setAttribute("data-screen", "result");
  const box = $("div", { "data-aios-result": "1", style: { maxWidth: "40rem", margin: "0 auto", display: "flex", flexDirection: "column", gap: sp(4) } });

  // (1) HERO: the main card, with its Share / Add-to-bio / market affordances
  // INSIDE the card frame (FIX 2,3,4,6). The card shows the full reading.
  if (CONFIG.hasCard) {
    box.appendChild(buildCardElement(reading, { label: CONFIG.productName, mainBio: reading.bio_line }));
  } else {
    // No card (e.g. a diagnostic): the result fields are the teaser.
    box.appendChild(renderFields(reading, CONFIG.resultFields.slice(0, 3), "teaser"));
  }

  // (2) the email ask (unlocks the bonus cards) - or, when there is no capture,
  // the full reveal now (no card products show the polished reading here).
  if (CONFIG.capture.enabled) {
    box.appendChild(renderCapture(reading, ctx));
  } else if (!CONFIG.hasCard) {
    box.appendChild(renderReading(reading, pickFields(reading)));
    box.setAttribute("data-aios-full", "1");
  } else {
    box.setAttribute("data-aios-full", "1"); // the card IS the full result
  }

  // (3) the quiet page-footer "More from MacLean Market" link.
  const ml = renderMarketLink();
  if (ml) box.appendChild(ml);

  r.appendChild(box);
}

function renderFields(reading, fields, tag) {
  const wrap = $("div", { "data-aios-fields": tag, style: { display: "flex", flexDirection: "column", gap: sp(3) } });
  for (const f of fields) {
    const v = reading[f];
    if (v == null || v === "") continue;
    const val = Array.isArray(v) ? v.join(" \u00b7 ") : String(v);
    wrap.appendChild($("div", null, [ $("strong", null, [fieldLabel(f) + ": "]), val ]));
  }
  return wrap;
}

// ---- capture: write to CRM BEFORE revealing the full reading ----
function renderCapture(reading, ctx) {
  const wrap = $("div", { "data-aios-capture": "1", style: { display: "flex", flexDirection: "column", gap: sp(2), padding: sp(4), border: "1px solid var(--aios-color-border,#ccc)", borderRadius: "var(--aios-radius-md,6px)" } });
  // The TEASE: name the reward in enticing plain copy - the hook that earns the email.
  wrap.appendChild($("p", { class: "aios-tease", "data-aios-tease": "1" }, [captureTeaseText()]));
  const email = $("input", { type: "email", "data-aios-email": "1", placeholder: "you@example.com", required: "true", style: { padding: sp(3), fontSize: "1rem", border: "1px solid var(--aios-color-border,#ccc)", borderRadius: "var(--aios-radius-md,6px)", boxSizing: "border-box", width: "100%", maxWidth: "100%" } });
  const unlockLabel = (CONFIG.rewardCards || []).length ? "Unlock my bonus cards" : "Unlock my full result";
  const btn = $("button", { type: "button", "data-aios-capture-submit": "1", style: { padding: sp(3), border: "0", borderRadius: "var(--aios-radius-md,6px)", background: "var(--aios-color-accent,#2563eb)", color: "#fff", cursor: "pointer", fontWeight: "700" } }, [unlockLabel]);
  const note = $("p", { "aria-live": "polite", style: { minHeight: "1.2em", fontSize: "0.9rem", opacity: "0.8" } });
  btn.addEventListener("click", async () => {
    const addr = (email.value || "").trim();
    if (!/.+@.+\..+/.test(addr)) { note.textContent = "Please enter a valid email."; return; }
    btn.disabled = true; note.textContent = "Saving...";
    const archetype = reading.archetype_name || reading.overall_grade || reading.archetype || "result";
    const tags = deriveTags(reading, ctx);
    try {
      // Relative path (not "/capture"): resolves to /capture on the real server
      // (page served at /) AND to .../capture under a preview base path, so the
      // built app is walkable both live and in the at-the-gate preview.
      const res = await fetch("capture", { method: "POST", headers: { "content-type": "application/json" },
        body: JSON.stringify({ email: addr, first_name: (ctx && ctx.firstName) || "", archetype: archetype, tags: tags }) });
      if (!res.ok) throw new Error("capture failed");
      // Only AFTER the capture is recorded do the bonus cards reveal - each a full
      // card with its OWN in-card Share / Add-to-bio / market affordances. The main
      // card (already shown) carries the full reading + its own bio, so there is no
      // separate reading panel or bio section any more.
      const box = wrap.parentNode;
      wrap.remove();
      const mlEl = box.querySelector(".aios-market-wrap");
      const insert = (el) => { if (mlEl) box.insertBefore(el, mlEl); else box.appendChild(el); };
      if ((CONFIG.rewardCards || []).length) {
        const rewardWrap = $("div", { "data-aios-rewards": "1", style: { display: "flex", flexDirection: "column", gap: sp(4) } });
        renderRewardCards(reading, rewardWrap);
        insert(rewardWrap);
      }
      box.setAttribute("data-aios-full", "1");
    } catch (e) { btn.disabled = false; note.textContent = "Could not save right now - try again."; }
  });
  wrap.appendChild(email); wrap.appendChild(btn); wrap.appendChild(note);
  return wrap;
}

function deriveTags(reading, ctx) {
  const tags = [];
  const arch = reading.archetype_name || reading.overall_grade || reading.archetype;
  if (arch) tags.push(String(arch).toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, ""));
  // answer-derived: a couple distinctive words from the user's answers
  const words = ((ctx && ctx.answers) || []).join(" ").toLowerCase().match(/[a-z]{5,}/g) || [];
  for (const w of [...new Set(words)].slice(0, 3)) tags.push(w);
  return tags;
}

function injectResponsiveReset() {
  const style = document.createElement("style");
  // Mobile-clean by construction: nothing exceeds the viewport, no horizontal
  // scroll, and reduced-motion is honored (we add no animations, but declare it).
  style.textContent = "html,body{margin:0;max-width:100%;overflow-x:hidden}" +
    // FIX 1 (Wave 2.2): the LIGHT page now comes from the scaffold (<html
    // data-aios-theme=light> + a light-gradient body inline, which the kit can no
    // longer flip to dark). Here we only guarantee dark-on-light text everywhere
    // in the app root, and keep the cards white-on-gradient.
    "body{color:#1b2333}" +
    "#aios-app-root{box-sizing:border-box;max-width:100%;padding:var(--aios-space-4,1rem);color:#1b2333}" +
    "#aios-app-root h1,#aios-app-root h2,#aios-app-root h3,#aios-app-root label,#aios-app-root p,#aios-app-root li,#aios-app-root strong,#aios-app-root span{color:#1b2333}" +
    "#aios-app-root .aios-tc,#aios-app-root .aios-tc *{color:#fff}" + // cards stay white-on-gradient
    "#aios-app-root .aios-tc .aios-incard-share{color:#1b2333}" + // the white in-card CTA needs dark text
    "#aios-app-root *{max-width:100%;box-sizing:border-box}" +
    "#aios-app-root img{height:auto}" +
    // Fix 1: a fun, readable QUESTION SCREEN (not a boring form). Bold dark
    // questions, inviting inputs with a clear focus state, a lively submit.
    ".aios-q{display:flex;flex-direction:column;gap:.45rem}" +
    ".aios-q-text{font-size:1.15rem;font-weight:700;line-height:1.35;color:#141b2b}" +
    ".aios-input{padding:.85rem 1rem;font-size:1rem;border:1.5px solid #cfd6e6;border-radius:12px;background:#fff;color:#141b2b;box-sizing:border-box;width:100%;max-width:100%;transition:border-color .15s,box-shadow .15s}" +
    ".aios-input::placeholder{color:#9aa4b8}" +
    ".aios-input:focus{outline:none;border-color:#6a8bff;box-shadow:0 0 0 4px rgba(106,139,255,.18)}" +
    ".aios-submit{margin-top:.4rem;padding:.95rem 1.4rem;font-size:1.05rem;font-weight:800;letter-spacing:.2px;border:0;border-radius:12px;color:#fff;background:linear-gradient(135deg,#7c3aed,#2563eb);cursor:pointer;box-shadow:0 12px 26px -10px rgba(37,99,235,.6)}" +
    ".aios-submit:hover{filter:brightness(1.06)}" +
    // FIX 2,3,4,6: the affordances INSIDE the card frame (data-no-share). White
    // text on the card gradient; the Share button is a clear white CTA that pops.
    ".aios-tc-actions{margin-top:1.15rem;padding-top:1rem;border-top:1px solid rgba(255,255,255,.28);display:flex;flex-direction:column;gap:.75rem}" +
    ".aios-incard-sharerow{display:flex;flex-direction:column;gap:.3rem}" +
    ".aios-incard-share{width:100%;padding:.8rem 1rem;border:0;border-radius:11px;font-size:1rem;font-weight:800;letter-spacing:.2px;cursor:pointer;color:#1b2333;background:#fff;box-shadow:0 8px 20px -8px rgba(0,0,0,.45)}" +
    ".aios-incard-share:hover{filter:brightness(.95)}" +
    // B3: the direct web-share intents (X / LinkedIn / native), a row of chips under
    // the primary copy button. Outlined on the card gradient, so the white copy CTA
    // stays the clear primary.
    ".aios-incard-intents{display:flex;gap:.4rem;flex-wrap:wrap}" +
    ".aios-incard-intent{flex:1 1 auto;text-align:center;padding:.5rem .7rem;border-radius:9px;border:1px solid rgba(255,255,255,.55);background:rgba(255,255,255,.12);color:#fff;font-size:.8rem;font-weight:700;text-decoration:none;cursor:pointer;white-space:nowrap}" +
    ".aios-incard-intent:hover{background:rgba(255,255,255,.26)}" +
    ".aios-incard-note{font-size:.74rem;opacity:.85;text-align:center;min-height:.9em;white-space:pre-wrap}" +
    ".aios-incard-bio{display:flex;flex-direction:column;gap:.28rem}" +
    ".aios-incard-biolabel{margin:0;font-size:.6rem;letter-spacing:.14em;text-transform:uppercase;opacity:.8}" +
    ".aios-incard-biotext{margin:0;font-size:.92rem;line-height:1.4}" +
    ".aios-incard-copyrow{display:flex;align-items:center;gap:.5rem;flex-wrap:wrap}" +
    ".aios-incard-copy{padding:.32rem .8rem;border-radius:8px;border:1px solid rgba(255,255,255,.6);background:rgba(255,255,255,.16);color:#fff;font-size:.78rem;font-weight:700;cursor:pointer}" +
    ".aios-incard-copy:hover{background:rgba(255,255,255,.3)}" +
    ".aios-incard-copynote{font-size:.72rem;opacity:.85}" +
    ".aios-incard-market{display:inline-block;font-size:.72rem;opacity:.82;color:#fff;text-decoration:none;border-bottom:1px solid rgba(255,255,255,.4);align-self:flex-start}" +
    ".aios-incard-market:hover{opacity:1}" +
    // The on-screen reading (NO-CARD products only) + the tease + the page-footer market link.
    ".aios-reading{display:flex;flex-direction:column;gap:1rem;margin-top:.3rem;padding:1.15rem 1.2rem;border-radius:14px;background:rgba(30,40,70,.05);border:1px solid rgba(30,40,70,.12)}" +
    ".aios-reading-label{margin:0 0 .3rem;font-size:.66rem;letter-spacing:.12em;text-transform:uppercase;opacity:.6}" +
    ".aios-reading-val{margin:0;font-size:1rem;line-height:1.55;white-space:pre-wrap}" +
    ".aios-reading-chips{display:flex;flex-wrap:wrap;gap:.4rem;margin:.1rem 0 0;padding:0;list-style:none}" +
    ".aios-reading-chip{padding:.28rem .7rem;border-radius:999px;font-size:.85rem;background:rgba(30,40,70,.08);border:1px solid rgba(30,40,70,.15)}" +
    ".aios-market-wrap{text-align:center;margin-top:.3rem}" +
    ".aios-market-link{display:inline-block;font-size:.8rem;opacity:.6;text-decoration:none;color:inherit;border-bottom:1px solid transparent}" +
    ".aios-market-link:hover{opacity:.95;border-bottom-color:currentColor}" +
    ".aios-tease{margin:0 0 .55rem;font-size:.98rem;font-weight:600;line-height:1.45}" +
    "@media (prefers-reduced-motion: reduce){*{animation:none!important;transition:none!important}}";
  document.head.appendChild(style);
}

function start() {
  const r = root();
  if (!r) return;
  injectResponsiveReset();
  renderQuestions();
}
if (document.readyState === "loading") document.addEventListener("DOMContentLoaded", start);
else start();
